frameParser:
function parse(frame) {
  const toBytes = (input) => {
    if (Array.isArray(input)) return input.map((value) => Number(value) & 0xFF);
    if (typeof Uint8Array !== 'undefined' && input instanceof Uint8Array) return Array.from(input);
    if (input && input.buffer instanceof ArrayBuffer) {
      return Array.from(new Uint8Array(input.buffer, input.byteOffset || 0, input.byteLength));
    }

    const text = String(input || '');
    const trimmed = text.trim();
    const compactHex = trimmed.replace(/0x/gi, '').replace(/[\s,;:_-]/g, '');
    if (compactHex.length >= 2 && compactHex.length % 2 === 0 && /^[0-9a-f]+$/i.test(compactHex)) {
      const result = [];
      for (let i = 0; i < compactHex.length; i += 2) {
        result.push(parseInt(compactHex.slice(i, i + 2), 16));
      }
      return result;
    }

    const result = [];
    for (let i = 0; i < text.length; i += 1) result.push(text.charCodeAt(i) & 0xFF);
    return result;
  };

  const FULL_FRAME_LENGTH = 5732;
  const CONTENT_LENGTH = 5728;
  const FRAME_DATA_LENGTH = 0x165D;
  const VIBRATION_SAMPLES = 2132;
  const STRAIN_SAMPLES = 160;
  const TEMPERATURE_SAMPLES = 2;
  const VIBRATION_OFFSET = 10;
  const STRAIN_OFFSET = 4274;
  const STRAIN_SAMPLE_BYTES = 9;
  const ADC_TEMPERATURE_OFFSET = 5714;
  const TMP117_TEMPERATURE_OFFSET = 5717;
  const CHECKSUM_OFFSET = 5727;

  let bytes = toBytes(frame);

  // Serial Studio normally removes delimiters. Also accept a complete 5732-byte frame.
  if (
    bytes.length === FULL_FRAME_LENGTH &&
    bytes[0] === 0x5A &&
    bytes[1] === 0xA5 &&
    bytes[FULL_FRAME_LENGTH - 2] === 0xDD &&
    bytes[FULL_FRAME_LENGTH - 1] === 0xEE
  ) {
    bytes = bytes.slice(2, FULL_FRAME_LENGTH - 2);
  }

  if (bytes.length !== CONTENT_LENGTH) return [];

  const readUInt16BE = (offset) => (bytes[offset] * 256) + bytes[offset + 1];
  const readInt16LE = (offset) => {
    let value = bytes[offset] + (bytes[offset + 1] * 256);
    if (value >= 0x8000) value -= 0x10000;
    return value;
  };
  const readSigned24BE = (offset) => {
    let value = (bytes[offset] * 65536) + (bytes[offset + 1] * 256) + bytes[offset + 2];
    if (value >= 0x800000) value -= 0x1000000;
    return value;
  };
  const ads24ToVoltage = (raw) => (raw * 2.5) / 8388608.0;
  const tmp117ToCelsius = (offset) => {
    let value = bytes[offset] + (bytes[offset + 1] * 256);
    if (value >= 0x8000) value -= 0x10000;
    return value * 0.0078125;
  };
  const vibrationToG = (raw) => raw * 0.000488;

  const frameLength = readUInt16BE(0);
  const deviceId = bytes[2];
  const functionCode = bytes[3];
  const vibrationCount = readUInt16BE(4);
  const strainCount = readUInt16BE(6);
  const temperatureCount = readUInt16BE(8);

  if (frameLength !== FRAME_DATA_LENGTH) return [];
  if (deviceId < 1 || deviceId > 4) return [];
  if (functionCode !== 0xDD) return [];
  if (
    vibrationCount !== VIBRATION_SAMPLES ||
    strainCount !== STRAIN_SAMPLES ||
    temperatureCount !== TEMPERATURE_SAMPLES
  ) return [];

  const receivedChecksum = bytes[CHECKSUM_OFFSET];

  const vibration = [];
  for (let i = 0; i < VIBRATION_SAMPLES; i += 1) {
    vibration.push(vibrationToG(readInt16LE(VIBRATION_OFFSET + (i * 2))));
  }

  // The PDF stores the three strain channels interleaved for each sample:
  // CH1[0], CH2[0], CH3[0], CH1[1], CH2[1], CH3[1], ...
  const strain1 = [];
  const strain2 = [];
  const strain3 = [];
  for (let i = 0; i < STRAIN_SAMPLES; i += 1) {
    const sampleOffset = STRAIN_OFFSET + (i * STRAIN_SAMPLE_BYTES);
    strain1.push(ads24ToVoltage(readSigned24BE(sampleOffset)));
    strain2.push(ads24ToVoltage(readSigned24BE(sampleOffset + 3)));
    strain3.push(ads24ToVoltage(readSigned24BE(sampleOffset + 6)));
  }

  const adcTemperature = ads24ToVoltage(readSigned24BE(ADC_TEMPERATURE_OFFSET));
  const tmp117Temperature = tmp117ToCelsius(TMP117_TEMPERATURE_OFFSET);

  return {
    title: 'Microsystem Bearing Data',
    datasets: [
      { index: 0, title: 'Vibration', value: vibration[vibration.length - 1], buffer: vibration, sampleRate: 5300 },
      { index: 1, title: 'Strain 1', value: strain1[strain1.length - 1], buffer: strain1, sampleRate: 400 },
      { index: 2, title: 'Strain 2', value: strain2[strain2.length - 1], buffer: strain2, sampleRate: 400 },
      { index: 3, title: 'Strain 3', value: strain3[strain3.length - 1], buffer: strain3, sampleRate: 400 },
      { index: 4, title: 'ADC Temperature', value: adcTemperature },
      { index: 5, title: 'TMP117 Temperature', value: tmp117Temperature }
    ],
    meta: {
      frameLength,
      deviceId,
      functionCode,
      vibrationCount,
      strainCount,
      temperatureCount,
      checksum: receivedChecksum,
      checksumMode: 'disabled'
    }
  };
}

